member.example:
Bind the MeshCollider convex property using a serialized binder field — the target MeshCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private MeshColliderConvexBinder _convex;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _convex;
    }


Bind the MeshCollider convex property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private MeshCollider _meshCollider;
        
        private MeshColliderConvexBinder Convex =>
            new(_meshCollider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _convex;
    }
